mapper.select:
SELECT site_code AS siteCode, user_id AS userId, user_account AS userAccount, currency AS currency, sum(amount) AS rechargeAmount FROM report_user_recharge_withdraw where type = 1 AND site_code = #{vo.siteCode}
AND day_str = #{vo.dateStr}
AND day_hour_millis >= #{vo.startTime}
AND day_hour_millis <= #{vo.endTime}
GROUP BY site_code,user_id ,user_account, currency

SELECT site_code AS siteCode, user_id AS userId, user_account AS userAccount, currency AS currency, sum(amount) AS rechargeAmount FROM report_user_recharge_withdraw where user_id = #{vo.userId} AND type = 1
AND day_hour_millis >= #{vo.startTime}
AND day_hour_millis <= #{vo.endTime}
GROUP BY site_code,user_id,user_account,currency

