SUM(IF(type = 2, amount, 0)) AS withdrawAmount,
SUM(settlement_fee_amount) AS settlementFeeAmount
FROM
report_user_recharge_withdraw
where
site_code = #{vo.siteCode}

    AND agent_id IN

        #{value}



    AND day_hour_millis  >=   #{vo.startTime}


    AND day_hour_millis  <=   #{vo.endTime}


