SELECT currency AS currency,
deposit_withdraw_way_id AS payMethodId,
SUM(IF(type = #{vo.type}, amount, 0)) AS amount,
SUM(settlement_fee_amount) AS settlementFeeAmount
from report_user_recharge_withdraw
where site_code = #{vo.siteCode}
and type = #{vo.type}

    AND day_hour_millis  >=   #{vo.startTime}


    AND day_hour_millis  <=   #{vo.endTime}


    AND currency = #{vo.currency}


    AND agent_id IN

        #{value}


GROUP BY deposit_withdraw_way_id,currency

SELECT t.user_id AS userId, t.type As type, t.user_account AS userAccount, t.agent_id AS agentId, t.agent_account AS agentAccount, t.currency as currency, SUM(t.nums) AS nums, SUM(t.amount) AS amount, SUM(t.large_nums) AS largeNums, SUM(t.large_amount) AS largeAmount, SUM(t.deposit_subordinates_nums) AS depositSubordinatesNums, SUM(t.deposit_subordinates_amount) AS depositSubordinatesAmount FROM report_user_recharge_withdraw t left join user_info a on t.user_id = a.user_id
AND a.site_code = #{vo.siteCode}
AND day_hour_millis >= #{vo.startTime}
AND day_hour_millis <= #{vo.endTime}
group by t.user_id,t.user_account,t.type,t.agent_id,t.agent_account,t.currency

select SUM(IF(type = 1, amount, 0)) AS rechargeAmount, SUM(IF(type = 2, amount, 0)) AS withdrawAmount, sum(way_fee_amount) as wayFeeAmount, sum(settlement_fee_amount) as settleFeeAmount, user_id as userId, currency as currency from report_user_recharge_withdraw where agent_id IN
#{value}
AND day_millis >= #{vo.startTime}
AND day_millis <= #{vo.endTime}
group by currency, user_id

